/**
 * SPEC-026: Prompts de IA personalizables — listado y restablecer
 * (AC-01..AC-05, AC-14..AC-16). Frontera de mocking: api.db del bridge.
 * Montado con SettingsPage real en MemoryRouter (patrón NoteTemplatesTab):
 * la pestaña "Prompts personalizados" se abre vía ?tab=custom-prompts.
 * Generated by QA Dev agent.
 */
import { render, screen, within, type RenderResult } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { MemoryRouter, Route, Routes } from 'react-router-dom'
import { Toaster } from '@/components/ui/sonner'
import { TooltipProvider } from '@/components/ui/tooltip'
import { SettingsPage } from '@/pages/SettingsPage'
import type { CustomPrompt, CustomPromptId } from '@/types/domain'
import { installMockApi, type MockApiHandle } from '../../helpers/mockApi'

let mockApi: MockApiHandle

/** Vistas del catálogo con la forma del bridge; los textos son fixtures. */
const DEFAULT_BODIES: Record<CustomPromptId, string> = {
  script: 'Eres un preparador experto de entrevistas de discovery.',
  note: 'Eres un sintetizador experto de entrevistas de discovery.',
  assistant: 'Eres el copiloto en tiempo real de un entrevistador.'
}

function promptView(id: CustomPromptId, overrides: Partial<CustomPrompt> = {}): CustomPrompt {
  return {
    id,
    defaultBody: DEFAULT_BODIES[id],
    lockedRules: `Reglas fijas de ${id}\n- Responde únicamente con el JSON pedido.`,
    overrideBody: null,
    updatedAt: null,
    ...overrides
  }
}

function allDefaults(): CustomPrompt[] {
  return [promptView('script'), promptView('note'), promptView('assistant')]
}

function setPrompts(prompts: CustomPrompt[]): void {
  vi.mocked(mockApi.api.db.listCustomPrompts).mockResolvedValue({ ok: true, data: prompts })
}

function renderSettings(initialEntry = '/settings?tab=custom-prompts'): RenderResult {
  return render(
    <TooltipProvider>
      <MemoryRouter initialEntries={[initialEntry]}>
        <Routes>
          <Route path="/settings" element={<SettingsPage />} />
        </Routes>
      </MemoryRouter>
      <Toaster />
    </TooltipProvider>
  )
}

/** El TooltipTrigger real de un botón disabled es su span envolvente (tabIndex 0). */
function tooltipWrapperOf(button: HTMLElement): HTMLElement {
  const wrapper = button.parentElement
  if (wrapper === null) {
    throw new Error('El botón deshabilitado debe estar envuelto por el TooltipTrigger')
  }
  return wrapper
}

beforeEach(() => {
  vi.clearAllMocks()
  mockApi = installMockApi()
  setPrompts(allDefaults())
})

describe('CustomPromptsTab', () => {
  describe('listing the catalog', () => {
    // SPEC-026 · AC-01
    it('renders the three prompts with name, description and a status badge each', async () => {
      renderSettings()

      expect(await screen.findByTestId('custom-prompts-list')).toBeInTheDocument()
      const rows: Array<[string, string, string]> = [
        [
          'custom-prompt-row-script',
          'Guión y objetivos',
          'Prepara el guión personalizado y los objetivos de cada entrevista'
        ],
        [
          'custom-prompt-row-note',
          'Nota de resumen',
          'Sintetiza la nota de resumen al cerrar la entrevista'
        ],
        [
          'custom-prompt-row-assistant',
          'Asistente en vivo',
          'Sugiere la siguiente jugada durante la llamada'
        ]
      ]
      for (const [testId, name, description] of rows) {
        const row = screen.getByTestId(testId)
        expect(within(row).getByText(name)).toBeInTheDocument()
        expect(within(row).getByText(description)).toBeInTheDocument()
        expect(within(row).getByText(/^(Default|Personalizado)$/)).toBeInTheDocument()
      }
    })

    // SPEC-026 · AC-02
    it('shows the "Default" badge when a prompt has no saved override', async () => {
      renderSettings()

      await screen.findByTestId('custom-prompts-list')
      expect(screen.getAllByText('Default')).toHaveLength(3)
      expect(screen.queryByText('Personalizado')).not.toBeInTheDocument()
    })

    // SPEC-026 · AC-03
    it('shows the "Personalizado" badge when a prompt has a saved override', async () => {
      setPrompts([
        promptView('script', {
          overrideBody: 'Persona propia.',
          updatedAt: '2026-07-10T10:00:00.000Z'
        }),
        promptView('note'),
        promptView('assistant')
      ])
      renderSettings()

      const scriptRow = await screen.findByTestId('custom-prompt-row-script')
      expect(within(scriptRow).getByText('Personalizado')).toBeInTheDocument()
      expect(screen.getAllByText('Default')).toHaveLength(2)
    })

    // SPEC-026 · AC-04
    it('shows skeletons while the prompt catalog is loading', async () => {
      vi.mocked(mockApi.api.db.listCustomPrompts).mockReturnValue(
        new Promise<never>(() => undefined)
      )
      const { container } = renderSettings()

      await screen.findByText(
        'Ajusta la persona y el enfoque con los que la IA prepara, asiste y resume tus entrevistas'
      )
      expect(container.querySelectorAll('[data-slot="skeleton"]').length).toBeGreaterThanOrEqual(3)
      expect(screen.queryByTestId('custom-prompts-list')).not.toBeInTheDocument()
    })

    // SPEC-026 · AC-05
    it('shows the error state with the message and a "Reintentar" button that reloads the catalog', async () => {
      const user = userEvent.setup()
      vi.mocked(mockApi.api.db.listCustomPrompts)
        .mockResolvedValueOnce({
          ok: false,
          error: { kind: 'storage', message: 'Fallo simulado al listar prompts' }
        })
        .mockResolvedValueOnce({ ok: true, data: allDefaults() })
      renderSettings()

      expect(await screen.findByText('Fallo simulado al listar prompts')).toBeInTheDocument()
      await user.click(screen.getByRole('button', { name: 'Reintentar' }))

      expect(vi.mocked(mockApi.api.db.listCustomPrompts)).toHaveBeenCalledTimes(2)
      expect(await screen.findByTestId('custom-prompts-list')).toBeInTheDocument()
    })
  })

  describe('resetting a prompt to default', () => {
    // SPEC-026 · AC-14
    it('opens the "Restablecer prompt" AlertDialog naming the prompt and its consequence', async () => {
      const user = userEvent.setup()
      setPrompts([
        promptView('script', {
          overrideBody: 'Persona propia.',
          updatedAt: '2026-07-10T10:00:00.000Z'
        }),
        promptView('note'),
        promptView('assistant')
      ])
      renderSettings()

      const scriptRow = await screen.findByTestId('custom-prompt-row-script')
      await user.click(within(scriptRow).getByRole('button', { name: 'Restablecer prompt' }))

      const dialog = await screen.findByRole('alertdialog')
      expect(
        within(dialog).getByRole('heading', { name: 'Restablecer prompt' })
      ).toBeInTheDocument()
      expect(
        within(dialog).getByText(
          /Se eliminará permanentemente tu texto personalizado y el prompt «Guión y objetivos» volverá al texto por defecto\./
        )
      ).toBeInTheDocument()
      expect(within(dialog).getByRole('button', { name: 'Cancelar' })).toBeInTheDocument()
      expect(within(dialog).getByRole('button', { name: 'Restablecer' })).toBeInTheDocument()
      expect(vi.mocked(mockApi.api.db.resetCustomPrompt)).not.toHaveBeenCalled()
    })

    // SPEC-026 · AC-15
    it('resets the prompt, switches the badge to "Default" and shows the "Prompt restablecido" toast after confirming', async () => {
      const user = userEvent.setup()
      setPrompts([
        promptView('script', {
          overrideBody: 'Persona propia.',
          updatedAt: '2026-07-10T10:00:00.000Z'
        }),
        promptView('note'),
        promptView('assistant')
      ])
      vi.mocked(mockApi.api.db.resetCustomPrompt).mockResolvedValue({
        ok: true,
        data: promptView('script')
      })
      renderSettings()

      const scriptRow = await screen.findByTestId('custom-prompt-row-script')
      await user.click(within(scriptRow).getByRole('button', { name: 'Restablecer prompt' }))
      const dialog = await screen.findByRole('alertdialog')
      await user.click(within(dialog).getByRole('button', { name: 'Restablecer' }))

      expect(vi.mocked(mockApi.api.db.resetCustomPrompt)).toHaveBeenCalledWith('script')
      expect(await within(scriptRow).findByText('Default')).toBeInTheDocument()
      expect(within(scriptRow).queryByText('Personalizado')).not.toBeInTheDocument()
      const toasts = await screen.findAllByText('Prompt restablecido')
      expect(toasts.length).toBeGreaterThanOrEqual(1)
    })

    // SPEC-026 · AC-16 (1 solo hover de tooltip por render — lección Radix)
    it('disables the "Restablecer prompt" button with an explanatory tooltip when the prompt is at default', async () => {
      const user = userEvent.setup()
      renderSettings()

      const scriptRow = await screen.findByTestId('custom-prompt-row-script')
      const resetButton = within(scriptRow).getByRole('button', { name: 'Restablecer prompt' })
      expect(resetButton).toBeDisabled()

      await user.hover(tooltipWrapperOf(resetButton))
      expect(
        (await screen.findAllByText('Este prompt ya usa el texto por defecto')).length
      ).toBeGreaterThanOrEqual(1)
    })
  })
})
